// ═══ Helpers ═══

function getAllKanji(level) {
  return KANJI_DATA[level].flatMap(g => g.kanji);
}

function getQuizReading(k) {
  if (k.kun.length > 0) {
    const raw = k.kun[0];
    const clean = raw.replace(/[()（）]/g, '');
    const hasOku = raw.includes('(') || raw.includes('（');
    
    // 1-char kun without okurigana
    if (!hasOku && clean.length === 1) {
      // Known legitimate 1-char standalone readings (N5 basics)
      const legit1char = {'め':1,'て':1,'き':1,'ひ':1,'こ':1,'な':1,'み':1,'え':1,'ち':1,'や':1,'ゆ':1};
      if (legit1char[clean] && k.m) {
        // Check if this kanji is a concrete noun (eye, hand, tree, fire, child)
        const concreteM = /eye|hand|tree|fire|child|ear|name|bud|blood|arrow|hot water|tooth|hair|leaf|rice paddy|nest|door/i;
        if (concreteM.test(k.m)) return clean;
      }
      // Otherwise use on'yomi
      if (k.on.length > 0) return toHiragana(k.on[0]);
      return clean;
    }
    
    // Standalone kun (no okurigana), 2-3 chars: やま、みず、くに
    if (!hasOku && clean.length >= 2 && clean.length <= 3) return clean;
    
    // Verb/adj with okurigana → prefer on'yomi if available, else use kun
    if (hasOku && clean.length <= 5) {
      if (k.on.length > 0) return toHiragana(k.on[0]);
      return clean;
    }
  }
  // On'yomi for abstract/compound kanji
  if (k.on.length > 0) return toHiragana(k.on[0]);
  // Last resort
  if (k.kun.length > 0) return k.kun[0].replace(/[()（）]/g, '');
  return '';
}

function toHiragana(str) {
  return str.replace(/[\u30A1-\u30F6]/g, ch =>
    String.fromCharCode(ch.charCodeAt(0) - 0x60)
  );
}
